-- ============================================================
-- IMAGO — locales/deDE/data/zones.lua
-- ============================================================

if GetLocale() ~= "deDE" then return end

IMAGOdb.zones[2405].name = "Leerensturm"
IMAGOdb.zones[2405].lore = "Uber die narbige Landschaft, die heute als der Leerensturm bekannt ist, ist nur wenig bekannt. Diese feindselige und fremdartige, zerbrochene Welt kannte einst Leben und Frieden. In vergangenen Zeiten waren die H\195\188gel und Felsvorspr\195\188nge Teil einer Welt namens Predacea. Als eine Gesellschaft des Wissens und des wissenschaftlichen Fortschritts war Predacea dennoch nicht immun gegen die Trommeln des Krieges. In dem Bestreben, jedem Konflikt ein Ende zu setzen, wurde eine Massenvernichtungswaffe entfesselt, die ihre Zivilisation g\195\164nzlich ausl\195\182schte. Unz\195\164hlige Jahre sp\195\164ter sind die \195\156berreste dieses Planeten zum Aufmarschgebiet f\195\188r Xal'ataths Krieg gegen Azeroth geworden."
IMAGOdb.zones[2405].pointsOfInterest = {
    {
        name = "Schlächteranhöhe",
        lore = "Der Gestank von frischem Blut erfüllt die Luft über den Ebenen der Schlächteranhöhe. Zwei Domanaar, Vidious und Ziadan, führen Krieg gegeneinander. Vordergründig kämpfen die beiden um die Kontrolle über das Territorium, doch die offensichtliche Freude, die beide am Blutvergießen empfinden, spielt zweifellos eine Rolle in ihren Plänen. Die beiden Widersacher haben gleichermaßen blutrünstige Mitglieder der Horde und der Allianz rekrutiert und schicken sie im Namen des Ruhms … oder zum bloßen Vergnügen in die Schlacht."
    },
    {
        name = "Sturmarionzitadelle",
        lore = "Die Sturmarionzitadelle thront am südwestlichen Rand des Leerensturms und blickt über eine endlose Weite aus zerklüfteten Canyons und totem Ödland. Ein Trupp von Ren'dorei-Forschern besetzt nun das Gebiet und versucht, die Vielzahl der um die Zitadelle verstreuten Singularitäten zu stabilisieren. Von allen Seiten durch Xal'ataths Streitkräfte bedroht, setzen diese tapferen Leerenelfen ihre Arbeit fort, ungeachtet des Preises."
    },
    {
        name = "Die Leerenspitze",
        lore = "Als Vollendung von Xal'ataths großem Plan ragt die Leerenspitze über den gesamten Leerensturm empor. Erschaffen aus der gefangenen Essenz von Dimensius dem Allesverzehrenden, ist die Leerenspitze ein Fokus dunkler Energie, wie ihn Azeroth noch nie zuvor gesehen hat. Hier zieht die Verschlingende Schar ihre Streitkräfte zusammen, um sich auf ihren unvermeidlichen letzten Angriff auf Quel'Thalas vorzubereiten."
    }
}

IMAGOdb.zones[2413].name = "Harandar"
IMAGOdb.zones[2413].lore = "Harandar ist die Heimat der Haranir, tief verborgen unter den gewaltigen Wurzelpfaden der Weltenbäume. Dieser biolumineszente Pilzdschungel ist ein Ort von urtümlicher Magie, dessen Bewohner als geheime Wächter Azeroths in vollkommener Harmonie mit der Natur leben. Doch die friedliche Existenz des Hara'ti-Stammes steht am Abgrund: Der Riss von Aln, eine urzeitliche Wunde, lässt die Grenze zwischen Traum und Realität verschwimmen und speit furchterregende Albträume aus. Gleichzeitig überwuchert die zerstörerische und fanatische Macht der Lichtblüte das Land, welche die heimische Flora korrumpiert."
IMAGOdb.zones[2413].pointsOfInterest = {
    {
        name = "Der Riss von Aln",
        lore = "Eine urzeitliche Wunde im Gefüge von Azeroth. Hier ist die Barriere zur Ebene der Träume so dünn, dass die Echos des Schmerzes der Göttin mächtig genug sind, um selbst den stärksten Geist in den Wahnsinn zu treiben."
    },
    {
        name = "Das Tal der Blendung",
        lore = "Ein schreckliches Zeugnis der jüngsten Bedrohung. Die Lichtblüte ist hier explosionsartig herangewachsen und verwandelt die einst friedlichen Rutaani unter der Führung des machthungrigen Lichthüters Ruia in blinde Fanatiker."
    },
    {
        name = "Der Bau der Echos",
        lore = "Das spirituelle und politische Herz von Harandar. Hier versammelt sich der Ältestenrat um Naynar, bewahrt die magischen Gemälde der Ahnen und orchestriert die Rettung der Wurzelpfade."
    },
}

IMAGOdb.zones[2437].name = "Zul'Aman"
IMAGOdb.zones[2437].lore = "Zul'Aman, die uralte Heimat der Amanitrolle, entfaltet sich als weitläufiges Gebiet voller dichter Wälder, hoher Berge und gnadenloser Wildnis. Unter der Führung von Zul'jarra, der Enkelin des legendären Zul'jin, versucht das einst stolze Volk verzweifelt, den Ansturm der Leere zu überleben. Der brüchige Frieden mit den benachbarten Blutelfen aus dem Immersangwald steht auf Messers Schneide, während Zul'jarra und ihr militanter Bruder Zul'jan mit dem schmerzhaften Verlust der Verbindung zu ihren Loa ringen. Inmitten dieser existenziellen Krise erheben sich vergessene Feinde aus dem Schatten, und die blutige Historie der Troll-Kultur offenbart sich jenen Entdeckern, die mutig genug sind, diese uralten Ländereien zu betreten."
IMAGOdb.zones[2437].pointsOfInterest = {
    {
        name = "Die verlassenen Loa-Tempel",
        lore = "Einst prachtvolle Schreine, die den mächtigen Geistern von Akil'zon (Adler), Halazzi (Luchs), Jan'alai (Drachenfalke) und Nalorakk (Bär) geweiht waren. Heute sind sie von Dschungelranken überwuchert und stehen als stumme Denkmäler einer schwindenden spirituellen Macht."
    },
    {
        name = "Die Maisara-Höhlen",
        lore = "Tief unter den heiligen Hügeln vollziehen extremistische Trolle der Vilebranch grausame Opferrituale an gefangenen Witherbark. Ihre verbotene Nekromantie speist einen monströsen Gräueltroll namens Rak'tul – eine tickende magische Zeitbombe, die ganz Zul'Aman ins Chaos stürzen könnte."
    },
    {
        name = "Der Zerbrochene Thron",
        lore = "Das architektonische und politische Herz der Zone. Hier koordiniert Zul'jarra verzweifelt den Widerstand. Umgeben von gigantischen Türmen, in denen wertvolle Artefakte und tödliche Rätsel verborgen liegen, entscheidet sich hier das Schicksal der Amani."
    },
}

IMAGOdb.zones[2395].name = "Immersangwald"
IMAGOdb.zones[2395].lore = "Der Immersangwald, das goldene Herz von Quel'Thalas und Heimat der Blutelfen. Diese atemberaubenden Lande wurden von vielen Tragödien gezeichnet, von denen die meisten durch die mächtige Magie des Sonnenbrunnens verursacht wurden, die jene verlockt, die seine Kraft für ihre eigenen finsteren Zwecke missbrauchen wollen. Nachdem Arthas eine Schneise aus Tod und Verfall durch das Zentrum des Waldes geschlagen hatte, glaubten viele, das Land würde sich nie erholen. Über Jahrzehnte hinweg jedoch gelang es den Magistern der Blutelfen, neues Leben zu kultivieren und Immersang zu seiner früheren Pracht zurückzuführen. Doch während die Verschlingende Horde von oben droht und die Lichtblüte aus der Tiefe hervorbricht, ist der Immersangwald von allen Seiten von Gefahren bedrängt."
IMAGOdb.zones[2395].pointsOfInterest = {
    {
        name = "Insel der Sonnenwanderer",
        lore = "Die Geschichten vieler heldenhafter Blutritter, Magister und Blutelfen aller Couleur begannen irgendwo. Die Insel der Sonnenwanderer dient seit Generationen als Lernort für junge Sin'dorei. Einst verlassen, fördert die hoch aufragende Akademie von Falthrien nun wieder frische Geister und vermittelt die Fertigkeiten, die jeder Abenteurer auf dem Weg vor ihm benötigt."
    },
    {
        name = "Dorf Morgenluft",
        lore = "Als eine der größten Siedlungen außerhalb Silbermonds dient Dorf Morgenluft als einflussreiches Handelszentrum im Immersangwald. Der nahegelegene Ankerplatz der Sonnensegel ist für viele der Im- und Exporte Quel'Thalas verantwortlich. Dieser geschäftige Ruf wird durch die Präsenz von Saltherils Hafen gestützt. Dieses weitläufige Anwesen neben dem Dorf beherbergt prunkvolle Galas und vereint die unterschiedlichen Klassen Silbermonds in Gesprächen und Zerstreuung. Doch da die Lichtblüte Ath'Ran von Süden her droht, riskiert Morgenluft dasselbe Schicksal wie Sonnenglanzdorf: vom unaufhörlichen Wachstum verschlungen zu werden."
    },
    {
        name = "Windläuferspitze",
        lore = "Einst Heim der gefeierten Windläuferfamilie, ist diese gewaltige Spitze seit den Tagen des Dritten Krieges von Feinden besetzt. Zuvor als Trophäe ihres Sieges von den Streitkräften der Geißel gehalten, liegt der Turm nun verlassen und reglos da, heimgesucht von den Gespenstern der Windläuferfamilie und ihren vielen Tragödien."
    },
}

IMAGOdb.zones[2424].name = "Insel von Quel'Danas"
IMAGOdb.zones[2424].lore = "Die Insel von Quel'Danas, das strahlende Kronjuwel des Elfenimperiums und Heimat des heiligen Sonnenbrunnens, ist zum ultimativen Schlachtfeld geworden. Xal'atath hat die gesamte Macht ihrer Leerenarmada hierher gelenkt, um den Quell aus Licht und arkaner Magie in ewige Finsternis zu stürzen. Der Himmel über der Insel ist von gigantischen kosmischen Rissen durchzogen, während sich Blut-, Hoch- und Leerenelfen zum ersten Mal seit Jahrtausenden vereinen. Schulter an Schulter stehen sie in einem verzweifelten letzten Gefecht, um das absolute Herz ihrer Zivilisation vor dem Untergang zu bewahren."
IMAGOdb.zones[2424].pointsOfInterest = {
    {
        name = "Der Sonnenbrunnen",
        lore = "Das magische Zentrum der Elfen und Xal'ataths primäres Ziel. Der Brunnen wurde massiv befestigt und pulsiert mit instabilen Energien, während die mächtigsten Magier Azeroths einen gewaltigen Schild gegen die alles verschlingende Leere aufrechterhalten."
    },
    {
        name = "Heiligtum der Sonnenweiten",
        lore = "Einst das Hauptquartier der Offensive der Zerschmetterten Sonne, wurde dieser Stützpunkt zu einer undurchdringlichen Festung ausgebaut. Hier koordinieren die vereinten Fraktionsführer die Verteidigung der gesamten Insel."
    },
    {
        name = "Die Morgensternfront",
        lore = "Die blutigen Strände der Insel, an denen Xal'ataths Invasionstruppen unablässig anlanden. Ein brutaler, nicht enden wollender Fleischwolf, in dem arkane Golems und Leerenbestien in einem endlosen Krieg aufeinanderprallen."
    },
}

IMAGOdb.zones[2393].name = "Silbermond"
IMAGOdb.zones[2393].lore = "Silbermond, das ewige Kronjuwel der Blutelfen, ist aus der Asche auferstanden und erneut zu einer blühenden Metropole geworden. Die Narben der Geißel und der Brennenden Legion ließen kaum etwas unversehrt, doch die talentierten Kunsthandwerker und Magister der großen Stadt haben sie zu ihrer früheren Pracht zurückgeführt. Nun, da die Bedrohung durch den Leerensturm über ihnen schwebt, sammeln die Sin'dorei ihre Verbündeten, um die Dunkelheit zurückzuschlagen, die die Stadt ein weiteres Mal dem Erdboden gleichmachen will."
IMAGOdb.zones[2393].pointsOfInterest = {
    {
        name = "Die Sonnenzornspitze",
        lore = "Die Sonnenzornspitze ist der Sitz der politischen Macht in Silbermond; Lor'themar Theron und seine Berater haben von ihren Zinnen aus die Richtung Quel'Thalas bestimmt. Stoisch über der Skyline von Silbermond aufragend, hat die Sonnenzornspitze den Test der Zeit bestanden und ist ein Zeugnis für die Widerstandskraft der Blutelfen."
    },
    {
        name = "Mördergasse",
        lore = "Auch wenn einige der Oberklasse von Silbermond es lieber ignorieren würden: Nicht jede Straße der Stadt ist sicher. In den schattigen Ecken der Mördergasse haben sich allerlei zwielichtige Gestalten niedergelassen. Hier experimentiert Astalor Blutschwur mit Qualen, einer vielversprechenden neuen Energiequelle. Ein beißender Schwefelgeruch liegt in der Luft und deutet auf die Präsenz dunkler Teufelsmagie in den tiefsten Winkeln hin."
    },
    {
        name = "Thalassische Universität",
        lore = "Silbermond war schon immer Vorreiter der arkanen Künste. Es waren die Elfen von Quel'Thalas, die der Menschheit erstmals zeigten, wie man die Arkane Macht selbst nutzt. In dieser Tradition umfasste der Wiederaufbau Silbermonds einen weitläufigen Universitätscampus. Hier wird die nächste Generation von Magiern unter der weisen Anleitung ihrer hochgeschätzten Professoren ausgebildet."
    },
}
